// Script: generar_33_cuidados_completos_5_grupos.js
// Que hace: completa la categoria Cuidados con los 15 items organizados
// en 5 grupos visuales (Cuidados basicos, Prevencion, Higiene y
// bienestar, Alimentacion, Eventos importantes), y agrega "Recibio
// medicamento" con el mismo patron de mini-formulario automatico que ya
// tenian vacuna y antiparasitario.
//
//   1) app/registro-diario/page.tsx (REEMPLAZA el existente) -- la
//      seccion de Cuidados ahora se ve organizada en 5 grupos con sus
//      encabezados. "Recibio medicamento" abre un mini-formulario
//      (nombre, proximo control opcional) y crea la fila en la tabla
//      medicamentos automaticamente. Los 8 items nuevos de Higiene,
//      Alimentacion y Eventos son checks simples, igual que los 4
//      basicos originales.
//
//   2) app/dashboard/page.tsx (REEMPLAZA el existente) -- las consultas
//      de "ultima vez" se generaron de forma dinamica para los 15
//      cuidados posibles (en vez de escribir cada consulta a mano),
//      facilitando agregar mas cuidados en el futuro.
//
//   3) components/DashboardContenido.tsx (REEMPLAZA el existente) -- la
//      seccion "Cuidados recientes" ahora muestra solo los primeros 4
//      por defecto, con un boton "Ver todo" que despliega el resto
//      organizado por grupo (mismo patron que las pestanas de
//      Prevencion), para no saturar el dashboard si se usan los 15.
//
// IMPORTANTE: este script POR SI SOLO no es suficiente. Antes de
// correrlo hay que ejecutar 06_cuidados_completos.sql en un NUEVO
// snippet de Supabase (agrega las 9 columnas booleanas que faltan).
//
// Como correrlo: node generar_33_cuidados_completos_5_grupos.js
// Confirma "OK" para los 3 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/registro-diario/page.tsx', "");
escribir('app/dashboard/page.tsx', "");
escribir('components/DashboardContenido.tsx', "");
